import React from 'react';

function SafetyIndicators() {
  return (
    <div className="space-y-2 text-sm">
      <p>💡 <strong>Lighting:</strong> 0.8</p>
      <p>🧑‍🤝‍🧑 <strong>Crowd Density:</strong> 0.7</p>
      <p>👮 <strong>Police Presence:</strong> 0.9</p>
      <p>⭐ <strong>Rating:</strong> 0.6</p>
    </div>
  );
}

export default SafetyIndicators;
